// // This module is designed to decrement a 3-bit value on each positive edge of the clock signal.
module ring_counter
    (
        input clk,
        input reset,
        output reg [2:0] q
    );

    always @(posedge clk or posedge reset) 
    begin
        if (reset)
            q <= 3'b001;
        else
            q <= {q[1:0], q[2]};
    end

endmodule
